"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  User,
  Plus,
  Loader2,
  ArrowLeft,
  Trash2,
  Edit,
  UserPlus,
  ToggleLeft,
  ToggleRight,
  ShieldAlert,
} from "lucide-react";

interface Doctor {
  id: string;
  name: string;
  email: string;
  phone: string;
  specialization: string;
  qualification: string;
  experience: number;
  consultationFee: number;
  bio: string | null;
  isAvailable: boolean;
}

export default function HospitalDoctorsCRUDPage() {
  const router = useRouter();
  const { user, isLoading } = useAuth();
  
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingDoc, setEditingDoc] = useState<Doctor | null>(null);

  // Form fields
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [specialization, setSpecialization] = useState("");
  const [qualification, setQualification] = useState("");
  const [experience, setExperience] = useState("");
  const [consultationFee, setConsultationFee] = useState("");
  const [bio, setBio] = useState("");
  const [isAvailable, setIsAvailable] = useState(true);

  const [formSaving, setFormSaving] = useState(false);
  const [formError, setFormError] = useState("");

  const fetchDoctors = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/hospitals/doctors");
      const data = await res.json();
      if (data.success) {
        setDoctors(data.data.doctors);
      }
    } catch (err) {
      console.error("Error fetching doctors:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!isLoading) {
      if (!user || user.role !== "HOSPITAL") {
        router.push("/login");
        return;
      }
      fetchDoctors();
    }
  }, [user, isLoading, router]);

  const openAddModal = () => {
    setEditingDoc(null);
    setName("");
    setEmail("");
    setPhone("");
    setSpecialization("");
    setQualification("");
    setExperience("");
    setConsultationFee("");
    setBio("");
    setIsAvailable(true);
    setFormError("");
    setModalOpen(true);
  };

  const openEditModal = (doc: Doctor) => {
    setEditingDoc(doc);
    setName(doc.name);
    setEmail(doc.email);
    setPhone(doc.phone);
    setSpecialization(doc.specialization);
    setQualification(doc.qualification);
    setExperience(doc.experience.toString());
    setConsultationFee(doc.consultationFee.toString());
    setBio(doc.bio || "");
    setIsAvailable(doc.isAvailable);
    setFormError("");
    setModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to remove this doctor from your roster?")) return;
    try {
      const res = await fetch(`/api/hospitals/doctors?id=${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (data.success) {
        fetchDoctors();
      } else {
        alert(data.error || "Failed to delete doctor.");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleToggleAvailability = async (doc: Doctor) => {
    try {
      const res = await fetch("/api/hospitals/doctors", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...doc,
          isAvailable: !doc.isAvailable,
        }),
      });
      const data = await res.json();
      if (data.success) {
        fetchDoctors();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormSaving(true);
    setFormError("");

    const payload = {
      id: editingDoc?.id,
      name,
      email,
      phone,
      specialization,
      qualification,
      experience,
      consultationFee,
      bio,
      isAvailable,
    };

    try {
      const res = await fetch("/api/hospitals/doctors", {
        method: editingDoc ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const data = await res.json();
      if (data.success) {
        setModalOpen(false);
        fetchDoctors();
      } else {
        setFormError(data.error || "Something went wrong saving doctor details.");
      }
    } catch (err) {
      setFormError("Connection error. Please try again.");
    } finally {
      setFormSaving(false);
    }
  };

  if (isLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-10 h-10 text-primary-600 animate-spin" />
          <p className="text-text-secondary text-sm">Loading doctor directory...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/dashboard")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <span className="text-lg font-bold text-text-primary">Doctor Roster</span>
          </div>
          <button
            onClick={openAddModal}
            className="inline-flex items-center gap-1.5 px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-colors cursor-pointer"
          >
            <UserPlus className="w-4 h-4" /> Add Doctor
          </button>
        </div>
      </header>

      {/* Roster list */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-text-primary">Manage Medical Staff</h1>
          <p className="text-sm text-text-secondary mt-1">Onboard specialists, specify consulting fees, and check availabilities.</p>
        </div>

        {doctors.length === 0 ? (
          <div className="bg-white border border-border rounded-2xl py-16 px-4 text-center">
            <User className="w-12 h-12 text-text-muted mx-auto mb-4 opacity-50" />
            <h3 className="text-lg font-bold text-text-primary mb-1">Roster is Empty</h3>
            <p className="text-sm text-text-secondary max-w-sm mx-auto mb-6">
              You haven't added any doctors yet. Onboard doctors to allow patients to book appointments.
            </p>
            <button
              onClick={openAddModal}
              className="inline-flex items-center gap-1.5 px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-colors cursor-pointer"
            >
              <UserPlus className="w-4 h-4" /> Add Doctor Now
            </button>
          </div>
        ) : (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {doctors.map((doc) => (
              <div
                key={doc.id}
                className="bg-white border border-border rounded-2xl p-5 hover-lift flex flex-col justify-between"
              >
                <div>
                  <div className="flex justify-between items-start mb-2">
                    <div>
                      <h3 className="font-bold text-text-primary text-base">{doc.name}</h3>
                      <p className="text-xs font-semibold text-primary-600 mt-0.5">{doc.specialization} • {doc.qualification}</p>
                    </div>
                    <button
                      onClick={() => handleToggleAvailability(doc)}
                      className="text-text-secondary hover:text-text-primary transition-colors p-1"
                      title={doc.isAvailable ? "Set Offline" : "Set Available"}
                    >
                      {doc.isAvailable ? (
                        <ToggleRight className="w-7 h-7 text-emerald-600" />
                      ) : (
                        <ToggleLeft className="w-7 h-7 text-text-muted" />
                      )}
                    </button>
                  </div>

                  <p className="text-xs text-text-secondary leading-relaxed line-clamp-3 mb-4 mt-2">
                    {doc.bio || "No description / bio provided."}
                  </p>

                  <div className="grid grid-cols-2 gap-2 bg-surface-secondary/50 rounded-xl p-3 mb-4 text-xs">
                    <div>
                      <span className="text-text-muted block mb-0.5">Experience</span>
                      <span className="font-semibold text-text-primary">{doc.experience} Years</span>
                    </div>
                    <div>
                      <span className="text-text-muted block mb-0.5">Consultation Fee</span>
                      <span className="font-semibold text-text-primary">₹{doc.consultationFee}</span>
                    </div>
                  </div>
                </div>

                <div className="pt-4 border-t border-border flex justify-between items-center text-xs">
                  <span className="text-text-muted">{doc.phone}</span>
                  <div className="flex items-center gap-1">
                    <button
                      onClick={() => openEditModal(doc)}
                      className="p-2 hover:bg-surface-secondary text-primary-600 hover:text-primary-800 rounded-lg transition-colors cursor-pointer"
                      title="Edit"
                    >
                      <Edit className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => handleDelete(doc.id)}
                      className="p-2 hover:bg-red-50 text-error hover:text-red-700 rounded-lg transition-colors cursor-pointer"
                      title="Delete"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Onboarding Modal */}
      {modalOpen && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-xs flex items-center justify-center p-4 z-50 animate-fade-in">
          <div className="bg-white border border-border rounded-2xl w-full max-w-lg shadow-xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-5 border-b border-border flex justify-between items-center bg-surface-secondary/20">
              <h3 className="font-bold text-text-primary text-base">
                {editingDoc ? "Edit Doctor Profile" : "Onboard New Doctor"}
              </h3>
              <button
                onClick={() => setModalOpen(false)}
                className="text-text-muted hover:text-text-primary text-xl font-bold cursor-pointer"
              >
                &times;
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-5 space-y-4 overflow-y-auto flex-1">
              {formError && (
                <div className="bg-red-50 border border-red-200 text-red-700 text-xs p-3 rounded-lg flex items-center gap-2 font-semibold">
                  <ShieldAlert className="w-4 h-4 flex-shrink-0" />
                  <span>{formError}</span>
                </div>
              )}

              <div className="space-y-4">
                {/* Doctor Name */}
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Full Name</label>
                  <input
                    type="text"
                    required
                    placeholder="e.g. Dr. Jane Doe"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  {/* Email */}
                  <div className="space-y-1.5">
                    <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Email Address</label>
                    <input
                      type="email"
                      required
                      placeholder="doc@hospital.com"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                    />
                  </div>

                  {/* Phone */}
                  <div className="space-y-1.5">
                    <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Contact Number</label>
                    <input
                      type="text"
                      required
                      placeholder="9999988888"
                      value={phone}
                      onChange={(e) => setPhone(e.target.value)}
                      className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  {/* Specialty */}
                  <div className="space-y-1.5">
                    <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Specialization</label>
                    <input
                      type="text"
                      required
                      placeholder="e.g. Cardiology"
                      value={specialization}
                      onChange={(e) => setSpecialization(e.target.value)}
                      className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                    />
                  </div>

                  {/* Qualification */}
                  <div className="space-y-1.5">
                    <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Qualifications</label>
                    <input
                      type="text"
                      required
                      placeholder="e.g. MD, MBBS"
                      value={qualification}
                      onChange={(e) => setQualification(e.target.value)}
                      className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  {/* Experience */}
                  <div className="space-y-1.5">
                    <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Experience (Years)</label>
                    <input
                      type="number"
                      required
                      placeholder="e.g. 5"
                      value={experience}
                      onChange={(e) => setExperience(e.target.value)}
                      className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                    />
                  </div>

                  {/* Consultation Fee */}
                  <div className="space-y-1.5">
                    <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Consultation Fee (₹)</label>
                    <input
                      type="number"
                      required
                      placeholder="e.g. 500"
                      value={consultationFee}
                      onChange={(e) => setConsultationFee(e.target.value)}
                      className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                    />
                  </div>
                </div>

                {/* Bio */}
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Biography / Description</label>
                  <textarea
                    rows={3}
                    placeholder="Short summary of medical background, expertise, or timings..."
                    value={bio}
                    onChange={(e) => setBio(e.target.value)}
                    className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                  />
                </div>
              </div>

              <div className="pt-4 border-t border-border flex justify-end gap-3.5">
                <button
                  type="button"
                  onClick={() => setModalOpen(false)}
                  className="px-4 py-2 border border-border text-text-secondary font-semibold text-xs rounded-xl hover:bg-surface-secondary transition-colors cursor-pointer"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={formSaving}
                  className="px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-colors flex items-center gap-1 cursor-pointer disabled:opacity-50"
                >
                  {formSaving ? (
                    <>
                      <Loader2 className="w-3.5 h-3.5 animate-spin" /> Saving...
                    </>
                  ) : (
                    "Save Doctor"
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
